import { collection, addDoc, query, where, getDocs } from "firebase/firestore";
import { db } from "../firebase";

export default function IssueSelect({ user, setSessionId }) {

  const startChat = async (issue) => {
    const q = query(
      collection(db, "users"),
      where("role", "==", "agent"),
      where("skills", "array-contains", issue),
      where("status", "==", "online")
    );

    const snap = await getDocs(q);
    const agent = snap.docs[0];

    const session = await addDoc(collection(db, "sessions"), {
      customerId: user.uid,
      agentId: agent.id,
      issue,
      priority: "high",
      status: "active",
      lastHeartbeat: Date.now()
    });

    setSessionId(session.id);
  };

  return (
    <>
      <h3>Select Issue</h3>
      <button onClick={() => startChat("payment")}>Payment</button>
      <button onClick={() => startChat("delivery")}>Delivery</button>
    </>
  );
}
